import React from "react";
import styles from "../../styles/Grid.module.css";

export default function Cell({ index, symbol, selected, onClick, disabled }) {
  const handleClick = () => {
    if (disabled) return;
    onClick(index);
  };

  return (
    <button
      type="button"
      className={`${styles.cell} ${selected ? styles.selected : ""}`}
      onClick={handleClick}
      disabled={disabled}
      aria-pressed={selected}
    >
      <span className={styles.symbol}>{symbol}</span>
    </button>
  );
}
